SELECT dept_id deptid, sum( IFNULL( order_main_total_quantiy, 0 ) ) ordermaintotalquantiy, sum( IFNULL( order_sub_total_quantiy, 0 ) ) ordersubtotalquantiy, sum( IFNULL( stock_main_total_quanity, 0 ) ) stockmaintotalquanity, sum( IFNULL( stock_sub_total_quanity, 0 ) ) stocksubtotalquanity, sum( IFNULL( order_total_price, 0 ) ) ordertotalprice, sum( IFNULL( stock_total_price, 0 ) ) stocktotalprice, stat_date statdate FROM as_order_stock
AND stat_date >= #{startDate} AND stat_date <= #{endDate} AND stat_date = #{qryDate} AND dept_id = #{deptId}
GROUP BY dept_id,stat_date

SELECT dept_id deptid, sum( IFNULL( order_main_total_quantiy, 0 ) ) monthordermaintotalquantiy, sum( IFNULL( order_sub_total_quantiy, 0 ) ) monthordersubtotalquantiy, sum( IFNULL( stock_main_total_quanity, 0 ) ) monthstockmaintotalquanity, sum( IFNULL( stock_sub_total_quanity, 0 ) ) monthstocksubtotalquanity, sum( IFNULL( order_total_price, 0 ) ) monthordertotalprice, sum( IFNULL( stock_total_price, 0 ) ) monthstocktotalprice FROM as_order_stock
AND stat_date >= #{startDate} AND stat_date <= #{endDate} AND dept_id = #{deptId}
GROUP BY dept_id

SELECT dept_id deptid, spu_no spuno, sum( IFNULL( order_main_total_quantiy, 0 ) ) monthordermaintotalquantiy, sum( IFNULL( order_sub_total_quantiy, 0 ) ) monthordersubtotalquantiy, sum( IFNULL( stock_main_total_quanity, 0 ) ) monthstockmaintotalquanity, sum( IFNULL( stock_sub_total_quanity, 0 ) ) monthstocksubtotalquanity, sum( IFNULL( order_total_price, 0 ) ) monthordertotalprice, sum( IFNULL( stock_total_price, 0 ) ) monthstocktotalprice FROM as_order_stock
AND stat_date >= #{startDate} AND stat_date <= #{endDate} AND dept_id = #{deptId}
GROUP BY dept_id,spu_no

SELECT
    t1.dept_id deptid,
    t2.dept_name deptname
FROM
    as_order_stock t1,
    sys_dept t2

    t1.dept_id = t2.dept_id
    AND stat_date = #{qryDate}
    AND stat_date >= #{startDate}
    AND stat_date <= #{endDate}
    AND dept_id = #{deptId}

GROUP BY
    t1.dept_id

SELECT dept_id deptid, spu_no spuno, sum( IFNULL( order_main_total_quantiy, 0 ) ) ordermaintotalquantiy, sum( IFNULL( order_sub_total_quantiy, 0 ) ) ordersubtotalquantiy, sum( IFNULL( stock_main_total_quanity, 0 ) ) stockmaintotalquanity, sum( IFNULL( stock_sub_total_quanity, 0 ) ) stocksubtotalquanity, sum( IFNULL( order_total_price, 0 ) ) ordertotalprice, sum( IFNULL( stock_total_price, 0 ) ) stocktotalprice FROM as_order_stock
AND stat_date = #{qryDate} AND stat_date >= #{startDate} AND stat_date <= #{endDate} AND dept_id = #{deptId}
GROUP BY spu_no,dept_id

SELECT
    sum( CASE WHEN pay_status = '0' THEN sorting_price ELSE 0 END ) nopayamount,
    sum( CASE WHEN pay_status = '1' THEN sorting_price ELSE 0 END ) payamount
FROM
    store_goods_order t1
WHERE
    t1.status IN ('3','4')
AND t1.create_time >= #{startDate}
AND t1.create_time <= #{endDate}
AND t1.dept_id = #{deptId}
